{
  "name": "Indo-Africa B2B Architect",
  "description": "A professional blueprinting and documentation tool for the Indo-Africa B2B supply chain mobile platform, featuring backend architecture, database schemas, and API definitions."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppSection {
  Overview = 'overview',
  Backend = 'backend',
  Database = 'database',
  API = 'api',
  Flutter = 'flutter',
  Security = 'security'
}

export interface Endpoint {
  method: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  path: string;
  role: 'Admin' | 'Agent' | 'Both';
  description: string;
}

export interface TableField {
  name: string;
  type: string;
  constraints?: string;
  description: string;
}

export interface DatabaseTable {
  name: string;
  fields: TableField[];
}

import React, { useState, useEffect } from 'react';
import { AppSection } from './types';
import Sidebar from './components/Sidebar';
import Overview from './components/Overview';
import BackendArchitecture from './components/BackendArchitecture';
import DatabaseSchema from './components/DatabaseSchema';
import ApiEndpoints from './components/ApiEndpoints';
import FlutterStructure from './components/FlutterStructure';
import SecurityLogic from './components/SecurityLogic';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState<AppSection>(AppSection.Overview);

  useEffect(() => {
    const hash = window.location.hash.replace('#', '') as AppSection;
    if (Object.values(AppSection).includes(hash)) {
      setActiveSection(hash);
    }
  }, []);

  const handleSectionChange = (section: AppSection) => {
    setActiveSection(section);
    window.location.hash = section;
  };

  const renderContent = () => {
    switch (activeSection) {
      case AppSection.Overview: return <Overview />;
      case AppSection.Backend: return <BackendArchitecture />;
      case AppSection.Database: return <DatabaseSchema />;
      case AppSection.API: return <ApiEndpoints />;
      case AppSection.Flutter: return <FlutterStructure />;
      case AppSection.Security: return <SecurityLogic />;
      default: return <Overview />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        activeSection={activeSection} 
        onSectionChange={handleSectionChange} 
      />
      <main className="flex-1 p-8 ml-64 overflow-y-auto">
        <div className="max-w-5xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { AppSection } from '../types';

interface SidebarProps {
  activeSection: AppSection;
  onSectionChange: (section: AppSection) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeSection, onSectionChange }) => {
  const menuItems = [
    { id: AppSection.Overview, label: 'Project Overview', icon: 'fa-house' },
    { id: AppSection.Backend, label: 'Backend Architecture', icon: 'fa-server' },
    { id: AppSection.Database, label: 'Database Schema', icon: 'fa-database' },
    { id: AppSection.API, label: 'REST API Endpoints', icon: 'fa-code' },
    { id: AppSection.Flutter, label: 'Flutter Structure', icon: 'fa-mobile-screen' },
    { id: AppSection.Security, label: 'Security & Auth', icon: 'fa-shield-halved' },
  ];

  return (
    <aside className="fixed left-0 top-0 bottom-0 w-64 bg-slate-900 text-white p-6 z-50">
      <div className="flex items-center gap-3 mb-10 px-2">
        <div className="bg-blue-500 p-2 rounded-lg">
          <i className="fa-solid fa-earth-africa text-xl"></i>
        </div>
        <h1 className="text-xl font-bold leading-tight">B2B Supply Chain</h1>
      </div>

      <nav className="space-y-2">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => onSectionChange(item.id)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
              activeSection === item.id 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-white'
            }`}
          >
            <i className={`fa-solid ${item.icon} w-5`}></i>
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="absolute bottom-10 left-6 right-6 p-4 bg-slate-800 rounded-2xl">
        <p className="text-xs text-slate-400 uppercase tracking-wider mb-2 font-bold">Role context</p>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
          <span className="text-sm font-medium">Production Mode</span>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { Endpoint } from '../types';

const ApiEndpoints: React.FC = () => {
  const endpoints: Endpoint[] = [
    { method: 'POST', path: '/auth/login', role: 'Both', description: 'Exchange credentials for JWT' },
    { method: 'GET', path: '/suppliers', role: 'Both', description: 'List all Indian suppliers' },
    { method: 'POST', path: '/suppliers', role: 'Admin', description: 'Create new supplier profile' },
    { method: 'PATCH', path: '/suppliers/:id', role: 'Admin', description: 'Update supplier details' },
    { method: 'GET', path: '/buyers', role: 'Both', description: 'List all African buyers' },
    { method: 'POST', path: '/orders', role: 'Admin', description: 'Initiate new order flow' },
    { method: 'PATCH', path: '/orders/:id/status', role: 'Admin', description: 'Advance order lifecycle status' },
    { method: 'GET', path: '/reports/summary', role: 'Admin', description: 'Dashboard analytics for management' },
  ];

  const getMethodColor = (method: string) => {
    switch (method) {
      case 'GET': return 'bg-emerald-100 text-emerald-700';
      case 'POST': return 'bg-blue-100 text-blue-700';
      case 'PUT': return 'bg-amber-100 text-amber-700';
      case 'PATCH': return 'bg-indigo-100 text-indigo-700';
      case 'DELETE': return 'bg-rose-100 text-rose-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
      <h2 className="text-3xl font-bold text-slate-900 mb-6">REST API Endpoints</h2>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200 text-xs font-bold uppercase text-slate-500">
              <tr>
                <th className="px-6 py-4">Method</th>
                <th className="px-6 py-4">Endpoint</th>
                <th className="px-6 py-4">Required Role</th>
                <th className="px-6 py-4">Purpose</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {endpoints.map((ep, idx) => (
                <tr key={idx} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-md text-[10px] font-black tracking-widest ${getMethodColor(ep.method)}`}>
                      {ep.method}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-mono text-slate-900 font-medium">
                    {ep.path}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      ep.role === 'Admin' ? 'bg-rose-50 text-rose-600 border border-rose-100' : 
                      ep.role === 'Agent' ? 'bg-sky-50 text-sky-600 border border-sky-100' : 
                      'bg-slate-50 text-slate-600 border border-slate-200'
                    }`}>
                      {ep.role}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-slate-600 italic">
                    {ep.description}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="mt-8 p-6 bg-indigo-50 rounded-3xl border border-indigo-100">
        <h4 className="font-bold text-indigo-900 flex items-center gap-2 mb-2">
          <i className="fa-solid fa-circle-info"></i>
          Request Structure Tip
        </h4>
        <p className="text-indigo-800 text-sm">
          All requests (except /login) must include the <code>Authorization: Bearer &lt;token&gt;</code> header. 
          The backend uses <strong>Class-Validator</strong> to ensure payloads match the expected DTO shape before reaching the controller.
        </p>
      </div>
    </div>
  );
};

export default ApiEndpoints;

export enum AppScreen {
  Dashboard = 'dashboard',
  Suppliers = 'suppliers',
  Buyers = 'buyers',
  Orders = 'orders',
  Reports = 'reports',
  Login = 'login'
}

export type Role = 'ADMIN' | 'AGENT';

export interface User {
  id: string;
  name: string;
  role: Role;
  email: string;
}

export interface Supplier {
  id: string;
  name: string;
  location: string;
  products: string[];
  contact: string;
  person: string;
}

export interface Buyer {
  id: string;
  name: string;
  country: string;
  requirements: string;
  contact: string;
}

export type OrderStatus = 'Quotation Sent' | 'Quotation Approved' | 'Order Confirmed' | 'Processing' | 'Shipped' | 'Delivered';

export interface Order {
  id: string;
  supplierName: string;
  buyerName: string;
  product: string;
  quantity: string;
  status: OrderStatus;
  date: string;
}

import React, { useState, useEffect } from 'react';
import { AppScreen, Role, User } from './types';
import Login from './screens/Login';
import Dashboard from './screens/Dashboard';
import Suppliers from './screens/Suppliers';
import Buyers from './screens/Buyers';
import Orders from './screens/Orders';
import Reports from './screens/Reports';
import BottomNav from './components/BottomNav';
import Header from './components/Header';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.Dashboard);

  const handleLogin = (selectedRole: Role) => {
    setUser({
      id: '1',
      name: selectedRole === 'ADMIN' ? 'Admin User' : 'Agent User',
      role: selectedRole,
      email: selectedRole === 'ADMIN' ? 'admin@b2b.com' : 'agent@b2b.com'
    });
    setActiveScreen(AppScreen.Dashboard);
  };

  const handleLogout = () => {
    setUser(null);
    setActiveScreen(AppScreen.Login);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const renderScreen = () => {
    switch (activeScreen) {
      case AppScreen.Dashboard: return <Dashboard user={user} />;
      case AppScreen.Suppliers: return <Suppliers user={user} />;
      case AppScreen.Buyers: return <Buyers user={user} />;
      case AppScreen.Orders: return <Orders user={user} />;
      case AppScreen.Reports: return <Reports user={user} />;
      default: return <Dashboard user={user} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-24">
      <Header user={user} onLogout={handleLogout} />
      <main className="flex-1 overflow-y-auto p-4 max-w-lg mx-auto w-full">
        {renderScreen()}
      </main>
      <BottomNav 
        activeScreen={activeScreen} 
        setActiveScreen={setActiveScreen} 
        userRole={user.role}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { AppScreen, Role } from '../types';

interface BottomNavProps {
  activeScreen: AppScreen;
  setActiveScreen: (screen: AppScreen) => void;
  userRole: Role;
}

const BottomNav: React.FC<BottomNavProps> = ({ activeScreen, setActiveScreen, userRole }) => {
  const navItems = [
    { id: AppScreen.Dashboard, label: 'Home', icon: 'fa-house' },
    { id: AppScreen.Suppliers, label: 'Suppliers', icon: 'fa-box' },
    { id: AppScreen.Buyers, label: 'Buyers', icon: 'fa-users' },
    { id: AppScreen.Orders, label: 'Orders', icon: 'fa-file-invoice' },
    ...(userRole === 'ADMIN' ? [{ id: AppScreen.Reports, label: 'Stats', icon: 'fa-chart-pie' }] : [])
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-2 py-3 z-50 flex justify-around items-center safe-area-bottom">
      {navItems.map((item) => (
        <button
          key={item.id}
          onClick={() => setActiveScreen(item.id)}
          className={`flex flex-col items-center gap-1 min-w-[64px] transition-all ${
            activeScreen === item.id ? 'text-blue-600' : 'text-slate-400'
          }`}
        >
          <div className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all ${
            activeScreen === item.id ? 'bg-blue-50' : 'bg-transparent'
          }`}>
            <i className={`fa-solid ${item.icon} text-lg`}></i>
          </div>
          <span className="text-[10px] font-bold uppercase tracking-wider">{item.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default BottomNav;

