import React, { useState } from 'react';
import { User, Order, OrderStatus } from '../types';

const MOCK_ORDERS: Order[] = [
  { id: 'ORD-7712', supplierName: 'Jaipur Cotton Mills', buyerName: 'Kigali Garments Ltd', product: 'Raw Cotton Bundles', quantity: '500 KG', status: 'Shipped', date: 'Oct 24, 2023' },
  { id: 'ORD-7713', supplierName: 'Chennai Automotive', buyerName: 'Lagos Fleet Services', product: 'Engine Gaskets', quantity: '1,200 Units', status: 'Processing', date: 'Oct 25, 2023' },
  { id: 'ORD-7714', supplierName: 'Surat Silk Co', buyerName: 'Accra Fashion Hub', product: 'Pure Silk Sarees', quantity: '200 Pieces', status: 'Quotation Sent', date: 'Oct 26, 2023' },
];

const STATUS_ORDER: OrderStatus[] = ['Quotation Sent', 'Quotation Approved', 'Order Confirmed', 'Processing', 'Shipped', 'Delivered'];

const Orders: React.FC<{ user: User }> = ({ user }) => {
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-900">Orders</h2>
        {user.role === 'ADMIN' && (
          <button className="bg-indigo-600 text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-lg shadow-indigo-500/20 flex items-center gap-2">
            <i className="fa-solid fa-plus"></i> New Order
          </button>
        )}
      </div>

      <div className="space-y-4">
        {MOCK_ORDERS.map(order => (
          <div 
            key={order.id} 
            onClick={() => setSelectedOrder(order)}
            className={`bg-white p-5 rounded-3xl border transition-all ${selectedOrder?.id === order.id ? 'border-blue-500 ring-2 ring-blue-500/10' : 'border-slate-100 shadow-sm'}`}
          >
            <div className="flex justify-between items-start mb-3">
              <div>
                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{order.id}</span>
                <h3 className="font-bold text-slate-900 text-md mt-1">{order.product}</h3>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-slate-400 font-bold uppercase">{order.date}</p>
                <div className="text-xs font-bold text-slate-900 mt-1">{order.quantity}</div>
              </div>
            </div>

            <div className="flex items-center gap-2 text-xs text-slate-500 mb-4">
              <span className="truncate max-w-[100px]">{order.supplierName}</span>
              <i className="fa-solid fa-arrow-right-long text-[10px]"></i>
              <span className="truncate max-w-[100px]">{order.buyerName}</span>
            </div>

            <div className="flex items-center justify-between">
              <div className="flex -space-x-2">
                {[1, 2, 3].map(i => (
                  <div key={i} className="w-6 h-6 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[8px] font-bold text-slate-400">
                    {i}
                  </div>
                ))}
              </div>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></span>
                <span className="text-[11px] font-bold text-blue-600">{order.status}</span>
              </div>
            </div>

            {selectedOrder?.id === order.id && (
              <div className="mt-6 pt-6 border-t border-slate-100 animate-in fade-in duration-300">
                <h4 className="text-[10px] font-black text-slate-400 uppercase mb-4 tracking-widest">Order Timeline</h4>
                <div className="space-y-4 relative">
                   <div className="absolute left-[7px] top-2 bottom-2 w-0.5 bg-slate-100"></div>
                   {STATUS_ORDER.map((s, idx) => {
                     const isDone = STATUS_ORDER.indexOf(order.status) >= idx;
                     const isCurrent = order.status === s;
                     return (
                       <div key={s} className="flex items-center gap-4 relative z-10">
                         <div className={`w-4 h-4 rounded-full border-2 border-white shadow-sm ${isDone ? 'bg-blue-500' : 'bg-slate-200'}`}></div>
                         <span className={`text-xs ${isCurrent ? 'font-bold text-slate-900' : 'text-slate-400'}`}>{s}</span>
                         {isCurrent && <i className="fa-solid fa-chevron-left text-[8px] text-blue-500 animate-bounce-x"></i>}
                       </div>
                     );
                   })}
                </div>
                {user.role === 'ADMIN' && (
                   <div className="mt-6 grid grid-cols-2 gap-3">
                     <button className="py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest">Update Status</button>
                     <button className="py-3 bg-white border border-slate-200 text-slate-600 rounded-2xl text-[10px] font-bold uppercase tracking-widest">Edit Details</button>
                   </div>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default Orders;

import React from 'react';
import { User, Buyer } from '../types';

