import 'package:dio/dio.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class ApiService {
  final Dio _dio = Dio(BaseOptions(baseUrl: 'https://api.supplylink.com/v1'));
  final _storage = const FlutterSecureStorage();

  ApiService() {
    _dio.interceptors.add(InterceptorsWrapper(
      onRequest: (options, handler) async {
        String? token = await _storage.read(key: 'access_token');
        if (token != null) {
          options.headers['Authorization'] = 'Bearer $token';
        }
        return handler.next(options);
      },
    ));
  }

  Future<Response> login(String username, String password) async {
    return await _dio.post('/auth/login/', data: {
      'username': username,
      'password': password,
    });
  }

  Future<List<dynamic>> getOrders() async {
    final response = await _dio.get('/orders/');
    return response.data;
  }
}

import React, { useState } from 'react';
import { AppScreen, Role, User } from './types';
import Login from './screens/Login';
import Dashboard from './screens/Dashboard';
import Suppliers from './screens/Suppliers';
import Buyers from './screens/Buyers';
import Orders from './screens/Orders';
import Reports from './screens/Reports';
import BottomNav from './components/BottomNav';
import Header from './components/Header';
import CodeExplorer from './components/CodeExplorer';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.Dashboard);
  const [showCode, setShowCode] = useState(false);

  const handleLogin = (selectedRole: Role) => {
    setUser({
      id: '1',
      name: selectedRole === 'ADMIN' ? 'Admin User' : 'Agent User',
      role: selectedRole,
      email: selectedRole === 'ADMIN' ? 'admin@b2b.com' : 'agent@b2b.com'
    });
    setActiveScreen(AppScreen.Dashboard);
  };

  const handleLogout = () => {
    setUser(null);
    setActiveScreen(AppScreen.Login);
    setShowCode(false);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const renderScreen = () => {
    if (showCode) return <CodeExplorer />;

    switch (activeScreen) {
      case AppScreen.Dashboard: return <Dashboard user={user} />;
      case AppScreen.Suppliers: return <Suppliers user={user} />;
      case AppScreen.Buyers: return <Buyers user={user} />;
      case AppScreen.Orders: return <Orders user={user} />;
      case AppScreen.Reports: return <Reports user={user} />;
      default: return <Dashboard user={user} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-24">
      <Header 
        user={user} 
        onLogout={handleLogout} 
        showCode={showCode} 
        toggleCode={() => setShowCode(!showCode)} 
      />
      <main className="flex-1 overflow-y-auto p-4 max-w-lg mx-auto w-full">
        {renderScreen()}
      </main>
      <BottomNav 
        activeScreen={activeScreen} 
        setActiveScreen={(s) => { setActiveScreen(s); setShowCode(false); }} 
        userRole={user.role}
      />
    </div>
  );
};

export default App;

