      )}

      <div className="space-y-4">
        {displayOrders.length > 0 ? (
          displayOrders.map(order => (
            <div 
              key={order.id} 
              onClick={() => setSelectedOrder(order)}
              className={`bg-white p-5 rounded-3xl border transition-all ${selectedOrder?.id === order.id ? 'border-blue-500 ring-2 ring-blue-500/10' : 'border-slate-100 shadow-sm'}`}
            >
