  { id: 'B2', name: 'Lagos Fleet Services', country: 'Nigeria', requirements: 'Engine Parts, Oil', contact: '+234 800 111 2222', createdBy: '1' },
  { id: 'B3', name: 'Accra Fashion Hub', country: 'Ghana', requirements: 'Silk, Embroidery', contact: '+233 244 555 666', createdBy: '2' },
  { id: 'B4', name: 'Nairobi Logistics', country: 'Kenya', requirements: 'Tires, Hubs', contact: '+254 711 222 333', createdBy: '2' },
];

const Buyers: React.FC<{ user: User }> = ({ user }) => {
  const [buyers, setBuyers] = useState<Buyer[]>(INITIAL_BUYERS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBuyer, setEditingBuyer] = useState<Buyer | null>(null);

  // Form State
  const [formData, setFormData] = useState({ name: '', country: '', requirements: '', contact: '' });

  const displayBuyers = user.role === 'ADMIN' 
    ? buyers 
    : buyers.filter(b => b.createdBy === user.id);

  const openAddModal = () => {
    setEditingBuyer(null);
    setFormData({ name: '', country: '', requirements: '', contact: '' });
    setIsModalOpen(true);
  };

  const openEditModal = (buyer: Buyer) => {
    setEditingBuyer(buyer);
    setFormData({ name: buyer.name, country: buyer.country, requirements: buyer.requirements, contact: buyer.contact });
    setIsModalOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBuyer) {
      setBuyers(buyers.map(b => b.id === editingBuyer.id ? { ...b, ...formData } : b));
    } else {
      const newBuyer: Buyer = {
        id: `B${Date.now()}`,
        ...formData,
        createdBy: user.id
      };
      setBuyers([...buyers, newBuyer]);
    }
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this buyer?')) {
      setBuyers(buyers.filter(b => b.id !== id));
    }
  };

  return (
