        >
          <i className="fa-solid fa-plus"></i>
        </button>
      </div>

      {user.role === 'AGENT' && (
        <div className="bg-blue-50 border border-blue-100 p-3 rounded-2xl text-[10px] text-blue-600 font-bold flex items-center gap-2">
          <i className="fa-solid fa-circle-info"></i>
          OWNERSHIP FILTER ACTIVE
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        {displayBuyers.length > 0 ? (
          displayBuyers.map(buyer => (
            <div key={buyer.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
              <div className="w-14 h-14 rounded-2xl bg-emerald-50 text-emerald-600 flex items-center justify-center text-xl font-black">
                {buyer.name[0]}
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-slate-900 text-md">{buyer.name}</h3>
                  <div className="flex gap-2">
                    <button onClick={() => openEditModal(buyer)} className="text-slate-400 hover:text-blue-600 p-1">
                      <i className="fa-solid fa-pen-to-square text-xs"></i>
                    </button>
                    <button onClick={() => handleDelete(buyer.id)} className="text-slate-400 hover:text-rose-600 p-1">
                      <i className="fa-solid fa-trash text-xs"></i>
                    </button>
                  </div>
                </div>
                <p className="text-[11px] text-slate-500 mt-1 italic leading-tight">Needs: {buyer.requirements}</p>
                <div className="flex items-center justify-between mt-3">
                  <span className="text-[10px] text-slate-400 font-bold">{buyer.country} • {buyer.contact}</span>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center opacity-30">
            <i className="fa-solid fa-users text-4xl mb-4"></i>
            <p className="text-sm font-bold">No buyers found</p>
          </div>
        )}
