                <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg shadow-emerald-500/20 active:scale-95 transition-all mt-4">
                  {editingBuyer ? 'Save Changes' : 'Create Buyer Account'}
