              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Buyers;

import React, { useState } from 'react';
import { User, Supplier } from '../types';

const INITIAL_SUPPLIERS: Supplier[] = [
  { id: 'S1', name: 'Jaipur Cotton Mills', location: 'Rajasthan, IN', products: ['Textiles', 'Garments'], contact: '+91 987 654 3210', person: 'Rajiv Sharma' },
  { id: 'S2', name: 'Surat Silk Co', location: 'Gujarat, IN', products: ['Silk', 'Embroidery'], contact: '+91 912 345 6789', person: 'Priya Patel' },
  { id: 'S3', name: 'Chennai Automotive', location: 'Tamil Nadu, IN', products: ['Spare Parts', 'Batteries'], contact: '+91 944 555 6666', person: 'Vijay Kumar' },
  { id: 'S4', name: 'Bengaluru Tech Parts', location: 'Karnataka, IN', products: ['Semiconductors', 'PCB'], contact: '+91 802 333 4444', person: 'Anil Deshpande' },
];

const Suppliers: React.FC<{ user: User }> = ({ user }) => {
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSupplier, setEditingSupplier] = useState<Supplier | null>(null);

  // Form State
  const [formData, setFormData] = useState({ name: '', location: '', person: '', contact: '', products: '' });

  const filtered = suppliers.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.location.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openAddModal = () => {
    if (user.role !== 'ADMIN') return;
    setEditingSupplier(null);
    setFormData({ name: '', location: '', person: '', contact: '', products: '' });
    setIsModalOpen(true);
  };

  const openEditModal = (s: Supplier) => {
    if (user.role !== 'ADMIN') return;
    setEditingSupplier(s);
    setFormData({ name: s.name, location: s.location, person: s.person, contact: s.contact, products: s.products.join(', ') });
    setIsModalOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const productList = formData.products.split(',').map(p => p.trim()).filter(p => p !== '');

    if (editingSupplier) {
      setSuppliers(suppliers.map(s => s.id === editingSupplier.id ? { ...s, ...formData, products: productList } : s));
    } else {
      const newSup: Supplier = {
        id: `S${Date.now()}`,
        ...formData,
        products: productList
      };
      setSuppliers([...suppliers, newSup]);
    }
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (user.role !== 'ADMIN') return;
    if (confirm('Delete this supplier record?')) {
      setSuppliers(suppliers.filter(s => s.id !== id));
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-900">Suppliers</h2>
        {user.role === 'ADMIN' && (
          <button 
            onClick={openAddModal}
            className="bg-blue-600 text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/30 active:scale-90 transition-all"
          >
            <i className="fa-solid fa-plus"></i>
          </button>
        )}
      </div>

      <div className="relative">
        <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
        <input 
          type="text" 
          placeholder="Search vendors..."
          className="w-full pl-12 pr-4 py-4 bg-white rounded-3xl border border-slate-100 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all text-sm"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="space-y-4">
        {filtered.map(supplier => (
          <div key={supplier.id} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm hover:border-blue-200 transition-all group">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="font-bold text-slate-900 text-lg leading-tight">{supplier.name}</h3>
                <p className="text-slate-500 text-xs flex items-center gap-1 mt-1">
                  <i className="fa-solid fa-location-dot"></i> {supplier.location}
                </p>
              </div>
              <div className="flex items-center gap-2">
                {user.role === 'ADMIN' && (
                  <>
                    <button onClick={() => openEditModal(supplier)} className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 hover:text-blue-600 flex items-center justify-center">
                      <i className="fa-solid fa-pen text-[10px]"></i>
                    </button>
                    <button onClick={() => handleDelete(supplier.id)} className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600 flex items-center justify-center">
                      <i className="fa-solid fa-trash text-[10px]"></i>
                    </button>
                  </>
                )}
                <div className="bg-blue-50 text-blue-600 px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ml-1">India</div>
              </div>
            </div>

            <div className="flex flex-wrap gap-2 mb-4">
              {supplier.products.map(p => (
                <span key={p} className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-[10px] font-bold">
                  {p}
                </span>
              ))}
            </div>

            <div className="pt-4 border-t border-slate-50 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-slate-900 flex items-center justify-center text-white text-[10px] font-bold">
                  {supplier.person.split(' ').map(n => n[0]).join('')}
                </div>
                <div className="text-[11px]">
                  <p className="font-bold text-slate-900 leading-none">{supplier.person}</p>
                  <p className="text-slate-500 mt-1">{supplier.contact}</p>
                </div>
              </div>
              <button className="text-blue-600 w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center active:scale-90">
                <i className="fa-solid fa-phone text-xs"></i>
              </button>
            </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-end sm:items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom-10">
            <div className="p-8">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-900 uppercase">
                  {editingSupplier ? 'Edit Vendor' : 'New Supplier'}
                </h3>
                <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-900 p-2">
                  <i className="fa-solid fa-xmark text-xl"></i>
                </button>
              </div>

              <form onSubmit={handleSave} className="space-y-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Supplier Name</label>
                  <input 
                    required
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Location (India)</label>
                  <input 
                    required
                    value={formData.location}
                    onChange={e => setFormData({...formData, location: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    placeholder="City, State"
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Contact Person</label>
                    <input 
                      required
                      value={formData.person}
                      onChange={e => setFormData({...formData, person: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Phone</label>
                    <input 
                      required
                      value={formData.contact}
                      onChange={e => setFormData({...formData, contact: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    />
                  </div>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5">Products (Comma separated)</label>
                  <input 
                    required
                    value={formData.products}
                    onChange={e => setFormData({...formData, products: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                    placeholder="Cotton, Silk, Yarn..."
                  />
