                <button type="submit" className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg shadow-blue-500/20 active:scale-95 transition-all mt-4">
                  Save Vendor Record
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Suppliers;

import React, { useState } from 'react';
import { User, Order, OrderStatus } from '../types';

const INITIAL_ORDERS: Order[] = [
  { id: 'ORD-7712', supplierName: 'Jaipur Cotton Mills', buyerName: 'Kigali Garments Ltd', product: 'Raw Cotton Bundles', quantity: '500 KG', status: 'Shipped', date: 'Oct 24, 2023', createdBy: '1' },
  { id: 'ORD-7713', supplierName: 'Chennai Automotive', buyerName: 'Lagos Fleet Services', product: 'Engine Gaskets', quantity: '1,200 Units', status: 'Processing', date: 'Oct 25, 2023', createdBy: '1' },
  { id: 'ORD-7714', supplierName: 'Surat Silk Co', buyerName: 'Accra Fashion Hub', product: 'Pure Silk Sarees', quantity: '200 Pieces', status: 'Quotation Sent', date: 'Oct 26, 2023', createdBy: '2' },
];

const STATUS_ORDER: OrderStatus[] = ['Quotation Sent', 'Quotation Approved', 'Order Confirmed', 'Processing', 'Shipped', 'Delivered'];

const Orders: React.FC<{ user: User }> = ({ user }) => {
  const [orders, setOrders] = useState<Order[]>(INITIAL_ORDERS);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);

  // Form State
  const [formData, setFormData] = useState({ product: '', quantity: '', supplier: '', buyer: '', status: 'Quotation Sent' as OrderStatus });

  const displayOrders = user.role === 'ADMIN' 
    ? orders 
    : orders.filter(o => o.createdBy === user.id);

  const openAddModal = () => {
    setEditingOrder(null);
    setFormData({ product: '', quantity: '', supplier: '', buyer: '', status: 'Quotation Sent' });
    setIsModalOpen(true);
  };

  const openEditModal = (e: React.MouseEvent, order: Order) => {
    e.stopPropagation();
    setEditingOrder(order);
    setFormData({ 
      product: order.product, 
      quantity: order.quantity, 
      supplier: order.supplierName, 
      buyer: order.buyerName,
      status: order.status
    });
    setIsModalOpen(true);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this order permanently?')) {
      setOrders(orders.filter(o => o.id !== id));
      if (selectedOrder?.id === id) setSelectedOrder(null);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingOrder) {
      setOrders(orders.map(o => o.id === editingOrder.id ? { 
        ...o, 
        product: formData.product,
        quantity: formData.quantity,
        supplierName: formData.supplier,
        buyerName: formData.buyer,
        status: formData.status
      } : o));
    } else {
      const newOrder: Order = {
        id: `ORD-${Math.floor(1000 + Math.random() * 9000)}`,
        product: formData.product,
        quantity: formData.quantity,
        supplierName: formData.supplier,
        buyerName: formData.buyer,
        status: formData.status,
        date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
        createdBy: user.id
      };
      setOrders([newOrder, ...orders]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-900">Orders</h2>
        <button 
          onClick={openAddModal}
          className="bg-indigo-600 text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-lg shadow-indigo-500/20 flex items-center gap-2 active:scale-95 transition-all"
        >
          <i className="fa-solid fa-plus"></i> New Order
        </button>
      </div>

      <div className="space-y-4">
        {displayOrders.length > 0 ? (
          displayOrders.map(order => (
            <div 
              key={order.id} 
              onClick={() => setSelectedOrder(selectedOrder?.id === order.id ? null : order)}
              className={`bg-white p-5 rounded-3xl border transition-all cursor-pointer ${selectedOrder?.id === order.id ? 'border-blue-500 ring-4 ring-blue-500/5' : 'border-slate-100 shadow-sm'}`}
            >
              <div className="flex justify-between items-start mb-3">
                <div>
                  <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{order.id}</span>
                  <h3 className="font-bold text-slate-900 text-md mt-1">{order.product}</h3>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={(e) => openEditModal(e, order)} className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 hover:text-indigo-600 flex items-center justify-center transition-colors">
                    <i className="fa-solid fa-pen text-[10px]"></i>
                  </button>
                  <button onClick={(e) => handleDelete(e, order.id)} className="w-8 h-8 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600 flex items-center justify-center transition-colors">
                    <i className="fa-solid fa-trash text-[10px]"></i>
                  </button>
                </div>
              </div>

              <div className="flex items-center gap-2 text-xs text-slate-500 mb-4">
                <span className="truncate max-w-[100px] font-medium">{order.supplierName}</span>
                <i className="fa-solid fa-arrow-right-long text-[10px] opacity-30"></i>
                <span className="truncate max-w-[100px] font-medium">{order.buyerName}</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="text-[10px] text-slate-400 font-bold uppercase">{order.date} • {order.quantity}</div>
                <div className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full ${order.status === 'Delivered' ? 'bg-emerald-500' : 'bg-blue-500 animate-pulse'}`}></span>
                  <span className="text-[11px] font-bold text-blue-600">{order.status}</span>
                </div>
              </div>

              {selectedOrder?.id === order.id && (
                <div className="mt-6 pt-6 border-t border-slate-100 animate-in zoom-in-95 duration-300">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase mb-4 tracking-widest">Tracking Lifecycle</h4>
                  <div className="space-y-4 relative">
                    <div className="absolute left-[7px] top-2 bottom-2 w-0.5 bg-slate-100"></div>
                    {STATUS_ORDER.map((s, idx) => {
                      const isDone = STATUS_ORDER.indexOf(order.status) >= idx;
                      const isCurrent = order.status === s;
                      return (
