                          onClick={() => setFormData({...formData, status: s})}
                          className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                            formData.status === s 
                              ? 'bg-white text-blue-600 shadow-sm border border-blue-100' 
                              : 'text-slate-400 hover:text-slate-600'
                          }`}
                        >
                          {s}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>

                <button type="submit" className="w-full py-5 bg-blue-600 text-white rounded-[1.5rem] font-black uppercase tracking-[0.15em] text-xs shadow-xl shadow-blue-500/30 active:scale-95 transition-all mt-6 flex items-center justify-center gap-3">
                  <i className={`fa-solid ${editingAgent ? 'fa-user-check' : 'fa-user-plus'}`}></i>
                  {editingAgent ? 'Confirm Changes' : 'Create Agent Account'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

