import React, { useState } from 'react';
import { User } from '../types';

interface AgentInfo {
  id: string;
  name: string;
  username: string;
  password?: string;
  region: string;
  status: 'Online' | 'Offline' | 'Away';
  orders: number;
}

const INITIAL_AGENTS: AgentInfo[] = [
  { id: 'A1', name: 'Kwame Mensah', username: 'kwame_gh', password: 'password123', region: 'West Africa (Ghana)', status: 'Online', orders: 42 },
  { id: 'A2', name: 'Amara Diop', username: 'amara_sn', password: 'secure_sn_88', region: 'West Africa (Senegal)', status: 'Away', orders: 18 },
  { id: 'A3', name: 'John Okoro', username: 'john_drc', password: 'drc_login_2023', region: 'Central Africa (DRC)', status: 'Online', orders: 31 },
  { id: 'A4', name: 'Zainab Yusuf', username: 'zainab_ke', password: 'kenya_agent_42', region: 'East Africa (Kenya)', status: 'Offline', orders: 56 },
];

const Agents: React.FC<{ user: User }> = ({ user }) => {
  const [agents, setAgents] = useState<AgentInfo[]>(INITIAL_AGENTS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingAgent, setEditingAgent] = useState<AgentInfo | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [revealedPasswords, setRevealedPasswords] = useState<Record<string, boolean>>({});

  // Form State
  const [formData, setFormData] = useState({ 
    name: '', 
    username: '', 
    password: '', 
    region: '', 
    status: 'Offline' as 'Online' | 'Offline' | 'Away' 
  });

  if (user.role !== 'ADMIN') {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center p-8 text-center">
        <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center mb-4">
          <i className="fa-solid fa-shield-halved text-2xl"></i>
        </div>
        <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Access Restricted</h3>
        <p className="text-sm text-slate-500 mt-2 font-medium">Only administrators can manage the regional agent fleet.</p>
      </div>
    );
  }

  const toggleRevealPassword = (id: string) => {
    setRevealedPasswords(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const openAddModal = () => {
    setEditingAgent(null);
    setFormData({ name: '', username: '', password: '', region: '', status: 'Offline' });
    setShowPassword(true);
    setIsModalOpen(true);
  };

  const openEditModal = (a: AgentInfo) => {
    setEditingAgent(a);
    setFormData({ name: a.name, username: a.username, password: a.password || '', region: a.region, status: a.status });
    setShowPassword(true);
    setIsModalOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingAgent) {
      setAgents(agents.map(a => a.id === editingAgent.id ? { ...a, ...formData } : a));
    } else {
      const newAgent: AgentInfo = {
        id: `A${Date.now()}`,
        name: formData.name,
        username: formData.username,
        password: formData.password,
        region: formData.region,
        status: formData.status,
        orders: 0
      };
      setAgents([...agents, newAgent]);
    }
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Permanently deactivate and remove this agent\'s access?')) {
      setAgents(agents.filter(a => a.id !== id));
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
