    if (user.role !== 'ADMIN') return;
    setEditingSupplier(s);
    // Added defaults for optional fields to satisfy form state types
    setFormData({ 
      name: s.name, 
      location: s.location || '', 
      person: s.person || '', 
      contact: s.contact || '', 
      products: s.products.join(', ') 
    });
    setIsModalOpen(true);
