export enum AppScreen {
  Dashboard = 'dashboard',
  Suppliers = 'suppliers',
  Buyers = 'buyers',
  Orders = 'orders',
  Reports = 'reports',
  Login = 'login',
  Profile = 'profile',
  Agents = 'agents'
}

/**
 * AppSection enum for documentation and code explorer navigation.
 * Used in Sidebar.tsx and other documentation components.
 */
export enum AppSection {
  Overview = 'overview',
  Backend = 'backend',
  Database = 'database',
  API = 'api',
  Flutter = 'flutter',
  Security = 'security'
}

export type Role = 'ADMIN' | 'AGENT' | 'SUPPLIER';
export type AccountStatus = 'PENDING' | 'APPROVED' | 'REJECTED';

export interface User {
  id: string;
  name: string;
  role: Role;
  email: string;
  status?: AccountStatus;
}

/**
 * Database schema representation for documentation.
 */
export interface DatabaseField {
  name: string;
  type: string;
  constraints?: string;
  description: string;
}

export interface DatabaseTable {
  name: string;
  fields: DatabaseField[];
}

/**
 * REST API endpoint representation for documentation.
 */
export interface Endpoint {
  method: string;
  path: string;
  role: string;
  description: string;
}

/**
 * Supplier interface updated to support both detailed registration records
 * and simplified display records used in the dashboard.
 */
export interface Supplier {
  id: string;
  name: string; // Company Name
  personalName?: string;
  designation?: string;
  mobile?: string;
  telephone?: string;
  email?: string;
  address?: string;
  city?: string;
  state?: string;
  pinCode?: string;
  country?: string;
  website?: string;
  category?: string;
  iecCode?: string;
  gstNumber?: string;
  panNumber?: string;
  turnover?: string;
  brochureUrl?: string;
  paymentProofUrl?: string;
  status?: AccountStatus;
  products: string[];
  // Display fields used in screens/Suppliers.tsx
  location?: string;
  person?: string;
  contact?: string;
}

export interface Buyer {
  id: string;
  name: string;
  country: string;
  requirements: string;
  contact: string;
  createdBy: string;
}

export type OrderStatus = 
  | 'Quotation Sent' 
  | 'Quotation Approved' 
  | 'MOU Sign' 
  | 'Post Quotation Follow ups' 
  | 'Order Confirmed' 
  | 'Processing' 
  | 'Shipped' 
  | 'Delivered' 
  | 'Payment Terms' 
  | 'Payment Received' 
  | 'Commission Received';

export interface Order {
  id: string;
  supplierName: string;
  buyerName: string;
  product: string;
  quantity: string;
  amount: string;
  commission: string; // Admin only
  status: OrderStatus;
  date: string; // Order placed date
  expectedDeliveryDate: string;
  createdBy: string;
}

import React, { useState } from 'react';
import { AppScreen, Role, User } from './types';
import Login from './screens/Login';
import Dashboard from './screens/Dashboard';
import Suppliers from './screens/Suppliers';
import Buyers from './screens/Buyers';
import Orders from './screens/Orders';
import Reports from './screens/Reports';
import Profile from './screens/Profile';
import Agents from './screens/Agents';
import BottomNav from './components/BottomNav';
import Header from './components/Header';
import CodeExplorer from './components/CodeExplorer';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeScreen, setActiveScreen] = useState<AppScreen>(AppScreen.Dashboard);
  const [showCode, setShowCode] = useState(false);

  const handleLogin = (selectedRole: Role) => {
    setUser({
      id: Math.random().toString(36).substr(2, 9),
      name: selectedRole === 'ADMIN' ? 'Admin User' : selectedRole === 'SUPPLIER' ? 'Pending Supplier' : 'Agent User',
      role: selectedRole,
      email: `${selectedRole.toLowerCase()}@afroarab.com`,
      status: selectedRole === 'SUPPLIER' ? 'PENDING' : 'APPROVED'
    });
    setActiveScreen(AppScreen.Dashboard);
  };

  const handleLogout = () => {
    setUser(null);
    setActiveScreen(AppScreen.Login);
    setShowCode(false);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const renderScreen = () => {
    if (showCode) return <CodeExplorer />;

    switch (activeScreen) {
      case AppScreen.Dashboard: return <Dashboard user={user} />;
      case AppScreen.Suppliers: return <Suppliers user={user} />;
      case AppScreen.Buyers: return <Buyers user={user} />;
      case AppScreen.Orders: return <Orders user={user} />;
      case AppScreen.Reports: return <Reports user={user} />;
      case AppScreen.Agents: return <Agents user={user} />;
      case AppScreen.Profile: return <Profile user={user} onLogout={handleLogout} />;
      default: return <Dashboard user={user} />;
    }
  };

  return (
    <div className="h-[100dvh] bg-slate-50 flex flex-col overflow-hidden">
      <Header 
        user={user} 
        onLogout={handleLogout} 
        showCode={showCode} 
        toggleCode={() => setShowCode(!showCode)} 
      />

      <main className="flex-1 overflow-y-auto p-4 w-full max-w-lg mx-auto pb-32">
        {renderScreen()}
      </main>

      <BottomNav 
        activeScreen={activeScreen} 
        setActiveScreen={(s) => { setActiveScreen(s); setShowCode(false); }} 
        userRole={user.role}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { AppScreen, Role } from '../types';

interface BottomNavProps {
  activeScreen: AppScreen;
  setActiveScreen: (screen: AppScreen) => void;
  userRole: Role;
}

const BottomNav: React.FC<BottomNavProps> = ({ activeScreen, setActiveScreen, userRole }) => {
  const adminItems = [
    { id: AppScreen.Dashboard, label: 'Home', icon: 'fa-house' },
    { id: AppScreen.Buyers, label: 'Buyers', icon: 'fa-users' },
    { id: AppScreen.Suppliers, label: 'Vendors', icon: 'fa-box' },
    { id: AppScreen.Orders, label: 'Orders', icon: 'fa-file-invoice' },
    { id: AppScreen.Agents, label: 'Agents', icon: 'fa-user-tie' },
    { id: AppScreen.Profile, label: 'Profile', icon: 'fa-user' }
  ];

  const agentItems = [
    { id: AppScreen.Dashboard, label: 'Home', icon: 'fa-house' },
    { id: AppScreen.Buyers, label: 'Buyers', icon: 'fa-users' },
    { id: AppScreen.Suppliers, label: 'Vendors', icon: 'fa-box' },
    { id: AppScreen.Orders, label: 'Orders', icon: 'fa-file-invoice' },
    { id: AppScreen.Profile, label: 'Profile', icon: 'fa-user' }
  ];

  const supplierItems = [
    { id: AppScreen.Dashboard, label: 'Home', icon: 'fa-house' },
    { id: AppScreen.Buyers, label: 'Market', icon: 'fa-magnifying-glass-chart' },
    { id: AppScreen.Profile, label: 'Profile', icon: 'fa-user' }
  ];

  const getNavItems = () => {
    if (userRole === 'ADMIN') return adminItems;
    if (userRole === 'SUPPLIER') return supplierItems;
    return agentItems;
  };

  const navItems = getNavItems();
  const isHighDensity = navItems.length > 5;

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-lg border-t border-slate-200 px-1 py-3 z-[100] flex justify-around items-center safe-area-bottom shadow-[0_-4px_20px_rgba(0,0,0,0.05)]">
      {navItems.map((item) => (
        <button
          key={item.id}
          onClick={() => setActiveScreen(item.id)}
          className={`flex flex-col items-center gap-1 transition-all active:scale-95 touch-manipulation ${
            isHighDensity ? 'min-w-[44px]' : 'min-w-[64px]'
          } ${
            activeScreen === item.id ? 'text-blue-600' : 'text-slate-400'
          }`}
        >
          <div className={`flex items-center justify-center rounded-xl transition-all relative ${
            isHighDensity ? 'w-9 h-8' : 'w-12 h-10'
          } ${
            activeScreen === item.id ? 'bg-blue-50' : 'bg-transparent'
          }`}>
            <i className={`fa-solid ${item.icon} ${isHighDensity ? 'text-sm' : 'text-lg'}`}></i>
          </div>
          <span className={`${isHighDensity ? 'text-[7px]' : 'text-[9px]'} font-black uppercase tracking-tight`}>
            {item.label}
          </span>
          {activeScreen === item.id && (
            <div className="w-1 h-1 bg-blue-600 rounded-full mt-0.5"></div>
          )}
        </button>
      ))}
    </nav>
  );
};

export default BottomNav;

