    if (!isAdmin) return;
    setEditingSupplier(null);
    setFormData({ name: '', location: '', person: '', contact: '', products: '' });
    setIsModalOpen(true);
  };

  const openEditModal = (s: Supplier) => {
    if (!isAdmin) return;
    setEditingSupplier(s);
    setFormData({ 
      name: s.name, 
      location: s.location || '', 
      person: s.person || '', 
      contact: s.contact || '', 
      products: s.products.join(', ') 
    });
    setIsModalOpen(true);
