  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const productList = formData.products.split(',').map(p => p.trim()).filter(p => p !== '');

    if (editingSupplier) {
      setSuppliers(suppliers.map(s => s.id === editingSupplier.id ? { ...s, ...formData, products: productList } : s));
