                </div>
                <div>
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Lifecycle Status</label>
                   <select 
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as OrderStatus})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                   >
                     {FULL_LIFECYCLE.map(s => (
                       <option key={s} value={s} disabled={s === 'Commission Received' && user.role !== 'ADMIN'}>{s}</option>
                     ))}
                   </select>
                </div>

                <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-[0.15em] text-xs shadow-xl shadow-indigo-500/20 active:scale-95 transition-all mt-6">
                  {editingOrder ? 'Update Order Record' : 'Confirm & Initialize flow'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

