from rest_framework import serializers
from .models import Supplier, Buyer, Order, User

class UserSerializer(serializers.ModelSerializer):
    class Meta:
        model = User
        fields = ('id', 'username', 'email', 'role')

class SupplierSerializer(serializers.ModelSerializer):
    class Meta:
        model = Supplier
        fields = '__all__'

class BuyerSerializer(serializers.ModelSerializer):
    class Meta:
        model = Buyer
        fields = '__all__'

    def to_representation(self, instance):
        ret = super().to_representation(instance)
        request = self.context.get('request')

        # Security Logic: Suppliers see only needs and business activities
        if request and request.user.role == 'SUPPLIER':
            # Mask sensitive data
            visible_data = {
                'id': ret['id'],
                'company_name': "Verified Enterprise",
                'country': ret['country'],
                'business_activities': ret['business_activities'],
                'product_need': ret['product_need']
            }
            return visible_data

        return ret

class OrderSerializer(serializers.ModelSerializer):
    supplier_name = serializers.ReadOnlyField(source='supplier.company_name')
    buyer_name = serializers.ReadOnlyField(source='buyer.company_name')

    class Meta:
        model = Order
        fields = '__all__'

    def to_representation(self, instance):
        ret = super().to_representation(instance)
        request = self.context.get('request')

        # Agents/Suppliers shouldn't see Admin commissions
        if request and request.user.role != 'ADMIN':
            ret.pop('commission', None)

        return ret

