  const [currentTab, setCurrentTab] = useState<'Active' | 'Pending'>('Active');
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
