  const [selectedPending, setSelectedPending] = useState<Supplier | null>(null);

  const [formData, setFormData] = useState({
    name: '', personalName: '', designation: '', mobile: '', 
    telephone: '', email: '', address: '', city: '', state: '', 
    pinCode: '', country: 'India', website: '', category: '', 
    iecCode: '', gstNumber: '', panNumber: '', turnover: '',
    productsInput: '', brochureUrl: ''
  });

  const isAdmin = user.role === 'ADMIN';
  const isAgent = user.role === 'AGENT';
  const canManage = isAdmin || isAgent;

  const filtered = suppliers.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.location || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openAddModal = () => {
    if (!isAdmin) return;
    setEditingSupplier(null);
    setFormData({ 
      name: '', personalName: '', designation: '', mobile: '', 
      telephone: '', email: '', address: '', city: '', state: '', 
      pinCode: '', country: 'India', website: '', category: '', 
      iecCode: '', gstNumber: '', panNumber: '', turnover: '',
      productsInput: '', brochureUrl: ''
    });
    setIsModalOpen(true);
  };

