      name: s.name, 
      personalName: s.personalName || '',
      designation: s.designation || '',
      mobile: s.mobile || '',
      telephone: s.telephone || '',
      email: s.email || '',
      address: s.address || '',
      city: s.city || '',
      state: s.state || '',
      pinCode: s.pinCode || '',
      country: s.country || 'India',
      website: s.website || '',
      category: s.category || '',
      iecCode: s.iecCode || '',
      gstNumber: s.gstNumber || '',
      panNumber: s.panNumber || '',
