    e.stopPropagation();
    if (!isAdmin) return;
    if (confirm('Delete this supplier record?')) {
      setSuppliers(suppliers.filter(s => s.id !== id));
    }
  };

  const handleVettingDecision = (id: string, newStatus: AccountStatus) => {
    if (confirm(`Confirm ${newStatus.toLowerCase()} decision?`)) {
      const supplierToMove = pendingSuppliers.find(p => p.id === id);
      if (newStatus === 'APPROVED' && supplierToMove) {
