    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">
            {isSupplier ? 'My Fulfillment' : 'Order Pipeline'}
          </h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
            {isAgent ? `Supervisor: ${user.name}` : isSupplier ? `Company: ${user.name}` : 'Lifecycle Management'}
          </p>
        </div>
        {isAdmin && (
          <button 
            onClick={openAddModal}
            className="bg-indigo-600 text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-lg shadow-indigo-500/20 flex items-center gap-2 active:scale-95 transition-all"
          >
            <i className="fa-solid fa-plus"></i> New Supply Flow
          </button>
        )}
      </div>

      <div className="space-y-4">
        {displayOrders.length > 0 ? (
          displayOrders.map(order => (
            <div 
              key={order.id} 
              onClick={() => setSelectedOrder(selectedOrder?.id === order.id ? null : order)}
              className={`bg-white p-6 rounded-[2.5rem] border transition-all cursor-pointer ${selectedOrder?.id === order.id ? 'border-indigo-500 ring-4 ring-indigo-500/5' : 'border-slate-100 shadow-sm'}`}
            >
              <div className="flex justify-between items-start mb-4">
                <div>
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{order.id}</span>
                  <h3 className="font-bold text-slate-900 text-md mt-1">{order.product}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-tight">
                    Placed: {order.date} • Expected: {order.expectedDeliveryDate || 'TBD'}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  {isAdmin && (
                     <div className="flex gap-2">
                       <span className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded uppercase tracking-tighter self-center mr-2">
