  const isAdmin = user.role === 'ADMIN';
  const isAgent = user.role === 'AGENT';

  // Visibility Filter: Agents only see assigned buyers. Admins see all. Suppliers see all (masked).
  const visibleBuyers = buyers.filter(b => {
    if (isAdmin || isSupplier) return true;
    if (isAgent) return b.assignedAgent === user.name;
    return false;
  });

  const filtered = visibleBuyers.filter(b => 
    b.companyName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    b.country.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.businessActivities.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.productNeed.toLowerCase().includes(searchTerm.toLowerCase())
