  const openAddModal = () => {
    if (isSupplier) return;
    setEditingBuyer(null);
    setFormData({ name: '', companyName: '', designation: '', mobileNumber: '', country: '', businessActivities: '', productNeed: '', email: '', website: '', turnover: '', assignedAgent: isAgent ? user.name : '' });
