                      const isDone = FULL_LIFECYCLE.indexOf(order.status) >= FULL_LIFECYCLE.indexOf(s);
                      const isCurrent = order.status === s;
                      return (
                        <div key={s} className="flex items-center gap-5 relative z-10">
