                    <option value="">Assign Lead Agent</option>
                    {AGENT_OPTIONS.map(a => <option key={a} value={a}>{a}</option>)}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Product</label>
                    <input 
                      required
                      value={formData.product}
                      onChange={e => setFormData({...formData, product: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Quantity</label>
                    <input 
                      required
                      value={formData.quantity}
                      onChange={e => setFormData({...formData, quantity: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Amount ($)</label>
                    <input required value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-indigo-600 uppercase tracking-widest block mb-1.5 ml-1">Commission ($)</label>
                    <input required value={formData.commission} onChange={e => setFormData({...formData, commission: e.target.value})} className="w-full bg-indigo-50 border border-indigo-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Supplier Entity</label>
                  <input required value={formData.supplier} onChange={e => setFormData({...formData, supplier: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Buyer Entity</label>
                  <input required value={formData.buyer} onChange={e => setFormData({...formData, buyer: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                </div>

                <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-[0.15em] text-xs shadow-xl shadow-indigo-500/20 active:scale-95 transition-all mt-6">
                  {editingOrder ? 'Update Order Record' : 'Initialize Supply Flow'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

