                      <div>
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Official Website</label>
                        <input className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" value={formData.website} onChange={e => setFormData({...formData, website: e.target.value})} placeholder="https://..." />
                      </div>
                    </div>
                  </div>
                </div>

                {/* Section 3: Marketplace Data */}
                <div className="space-y-4 pt-2">
                  <label className="text-[9px] font-black text-emerald-600 uppercase tracking-[0.2em] block border-b border-emerald-50 pb-2">3. Sourcing Metrics</label>
                  <div>
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Commercial Landscape</label>
                    <textarea required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold h-20 resize-none outline-none focus:ring-2 focus:ring-emerald-500" value={formData.businessActivities} onChange={e => setFormData({...formData, businessActivities: e.target.value})} placeholder="Describe key sectors..." />
                  </div>
                  <div>
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Immediate Sourcing Needs (Public)</label>
                    <textarea required className="w-full bg-emerald-50/30 border border-emerald-100 rounded-2xl px-4 py-3 text-sm font-black h-24 resize-none outline-none focus:ring-2 focus:ring-emerald-500" value={formData.productNeed} onChange={e => setFormData({...formData, productNeed: e.target.value})} placeholder="Explicit active supply requests..." />
                  </div>
                  <div>
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">2Y Annual Turnover</label>
                    <input required className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-4 py-3 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none" value={formData.turnover} onChange={e => setFormData({...formData, turnover: e.target.value})} placeholder="e.g. $25M" />
                  </div>
                </div>

                <button type="submit" className="w-full py-5 bg-emerald-600 text-white rounded-[2rem] font-black uppercase tracking-[0.2em] text-xs shadow-xl shadow-emerald-500/20 active:scale-95 transition-all mt-6">
                  {editingBuyer ? 'Commit Changes' : 'Authorize Marketplace Listing'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Buyers;

import React, { useState } from 'react';
import { User, Order, OrderStatus } from '../types';

const INITIAL_ORDERS: Order[] = [
  { 
    id: 'ORD-7712', 
    supplierName: 'Jaipur Cotton Mills', 
    buyerName: 'Kigali Garments Ltd', 
    product: 'Raw Cotton Bundles', 
    quantity: '500 KG', 
    amount: '12,500', 
    commission: '1,250', 
    status: 'Shipped', 
    date: '2023-10-24', 
    expectedDeliveryDate: '2023-11-15', 
    createdBy: '1',
    assignedAgent: 'Kwame Mensah'
  },
  { 
    id: 'ORD-7713', 
    supplierName: 'Surat Silk Co', 
    buyerName: 'Lagos Fleet Services', 
    product: 'Engine Gaskets', 
    quantity: '1,200 Units', 
    amount: '8,200', 
    commission: '400', 
    status: 'Processing', 
    date: '2023-10-25', 
    expectedDeliveryDate: '2023-11-20', 
    createdBy: '1',
    assignedAgent: 'Amara Diop'
  },
];

const AGENT_OPTIONS = ['Kwame Mensah', 'Amara Diop', 'John Okoro', 'Zainab Yusuf'];

const FULL_LIFECYCLE: OrderStatus[] = [
  'Quotation Sent',
  'Quotation Approved',
  'MOU Sign',
  'Post Quotation Follow ups',
  'Order Confirmed',
  'Processing',
  'Shipped',
  'Delivered',
  'Payment Terms',
  'Payment Received',
  'Commission Received'
];

const Orders: React.FC<{ user: User }> = ({ user }) => {
  const [orders, setOrders] = useState<Order[]>(INITIAL_ORDERS);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);

  const [formData, setFormData] = useState({
    product: '',
    quantity: '',
    amount: '',
    commission: '',
    supplier: '',
    buyer: '',
    status: 'Quotation Sent' as OrderStatus,
    date: new Date().toISOString().split('T')[0],
    expectedDeliveryDate: '',
    assignedAgent: ''
  });

  const isAdmin = user.role === 'ADMIN';
  const isAgent = user.role === 'AGENT';
  const isSupplier = user.role === 'SUPPLIER';

  // Visibility Logic: Suppliers see only their own company orders
  const displayOrders = isAdmin 
    ? orders 
    : isAgent 
    ? orders.filter(o => o.assignedAgent === user.name)
    : orders.filter(o => o.supplierName === user.name);

  const getVisibleStages = () => {
    if (isAdmin) return FULL_LIFECYCLE;
    return FULL_LIFECYCLE.filter(s => s !== 'Commission Received');
  };

  const openAddModal = () => {
    if (!isAdmin) return;
    setEditingOrder(null);
    setFormData({
      product: '',
      quantity: '',
      amount: '',
      commission: '',
      supplier: '',
      buyer: '',
      status: 'Quotation Sent',
      date: new Date().toISOString().split('T')[0],
      expectedDeliveryDate: '',
      assignedAgent: isAgent ? user.name : ''
    });
    setIsModalOpen(true);
  };

  const openEditModal = (e: React.MouseEvent, order: Order) => {
    e.stopPropagation();
    if (!isAdmin) return;
    setEditingOrder(order);
    setFormData({
      product: order.product,
      quantity: order.quantity,
      amount: order.amount,
      commission: order.commission,
      supplier: order.supplierName,
      buyer: order.buyerName,
      status: order.status,
      date: order.date,
      expectedDeliveryDate: order.expectedDeliveryDate,
      assignedAgent: order.assignedAgent || ''
    });
    setIsModalOpen(true);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!isAdmin) return;
    if (confirm('Delete this order permanently?')) {
      setOrders(orders.filter(o => o.id !== id));
      if (selectedOrder?.id === id) setSelectedOrder(null);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingOrder) {
      setOrders(orders.map(o => o.id === editingOrder.id ? { 
        ...o, 
        ...formData,
        supplierName: formData.supplier,
        buyerName: formData.buyer,
      } : o));
    } else {
      const newOrder: Order = {
        id: `ORD-${Math.floor(1000 + Math.random() * 9000)}`,
        ...formData,
        supplierName: formData.supplier,
        buyerName: formData.buyer,
        createdBy: user.id
      };
      setOrders([newOrder, ...orders]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">
            {isSupplier ? 'Contract Archive' : 'Order Hub'}
          </h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
            {isAgent ? `Account Managed by ${user.name}` : isSupplier ? `Vendor Entity: ${user.name}` : 'Global Fulfillment Lifecycle'}
          </p>
        </div>
        {isAdmin && (
          <button 
            onClick={openAddModal}
            className="bg-indigo-600 text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-lg shadow-indigo-500/20 flex items-center gap-2 active:scale-95 transition-all"
          >
            <i className="fa-solid fa-plus"></i> Initiate Flow
          </button>
        )}
      </div>

      <div className="space-y-4">
        {displayOrders.length > 0 ? (
          displayOrders.map(order => (
            <div 
              key={order.id} 
              onClick={() => setSelectedOrder(selectedOrder?.id === order.id ? null : order)}
              className={`bg-white p-6 rounded-[2.5rem] border transition-all cursor-pointer ${selectedOrder?.id === order.id ? 'border-indigo-500 ring-4 ring-indigo-500/5' : 'border-slate-100 shadow-sm'}`}
            >
              <div className="flex justify-between items-start mb-4">
                <div>
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{order.id}</span>
                  <h3 className="font-bold text-slate-900 text-md mt-1">{order.product}</h3>
                  <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-tight">
                    Created: {order.date} • Expected: {order.expectedDeliveryDate || 'UNSET'}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  {isAdmin && (
                     <div className="flex gap-2">
                       <span className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded uppercase tracking-tighter self-center mr-2">
                          {order.assignedAgent || 'No Agent'}
                       </span>
                        <button onClick={(e) => openEditModal(e, order)} className="w-9 h-9 rounded-xl bg-slate-50 text-slate-400 hover:text-indigo-600 flex items-center justify-center transition-colors">
                          <i className="fa-solid fa-pen-nib text-xs"></i>
                        </button>
                        <button onClick={(e) => handleDelete(e, order.id)} className="w-9 h-9 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600 flex items-center justify-center transition-colors">
                          <i className="fa-solid fa-trash-can text-xs"></i>
                        </button>
                     </div>
                  )}
                  {isAgent && (
                    <span className="text-[9px] font-black text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-xl uppercase tracking-widest">Active Duty</span>
                  )}
                  {isSupplier && (
                    <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl uppercase tracking-widest">Master Agreement</span>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 mb-5 p-3 bg-slate-50 rounded-2xl border border-slate-100">
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-2">Vendor</p>
                  <p className="text-[11px] font-bold text-slate-900 truncate">{isSupplier ? 'Me (Secured)' : order.supplierName}</p>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-2">Customer Entity</p>
                  <p className="text-[11px] font-bold text-slate-900 truncate flex items-center gap-1">
                    {isSupplier ? (
                      <>
                        <i className="fa-solid fa-user-shield text-[9px] text-blue-500"></i>
                        Verified Client
                      </>
                    ) : order.buyerName}
                  </p>
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="text-right">
                      <div className="text-xs font-black text-slate-900">${order.amount}</div>
                      <div className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">Settlement Value</div>
                   </div>
                   {isAdmin && (
                     <div className="text-right border-l border-slate-200 pl-3">
                        <div className="text-xs font-black text-indigo-600">${order.commission}</div>
                        <div className="text-[8px] text-indigo-400 font-bold uppercase tracking-widest">Platform Fee</div>
                     </div>
                   )}
                </div>
                <div className="flex items-center gap-2">
                  <div className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${
                    order.status === 'Delivered' ? 'bg-emerald-100 text-emerald-700' : 'bg-indigo-100 text-indigo-700 animate-pulse'
                  }`}>
                    {order.status}
                  </div>
                </div>
              </div>

              {selectedOrder?.id === order.id && (
                <div className="mt-8 pt-8 border-t border-slate-100 animate-in zoom-in-95 duration-300">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase mb-6 tracking-widest flex items-center gap-2">
                    <i className="fa-solid fa-timeline"></i>
                    Fulfillment Lifecycle Status
                  </h4>
                  <div className="space-y-4 relative ml-2">
                    <div className="absolute left-[7px] top-2 bottom-2 w-0.5 bg-slate-100"></div>
                    {getVisibleStages().map((s, idx) => {
                      const isDone = FULL_LIFECYCLE.indexOf(order.status) >= FULL_LIFECYCLE.indexOf(s);
                      const isCurrent = order.status === s;
                      return (
                        <div key={s} className="flex items-center gap-5 relative z-10">
                          <div className={`w-4 h-4 rounded-full border-2 border-white shadow-sm transition-all duration-500 ${isDone ? 'bg-indigo-600 scale-110' : 'bg-slate-200'}`}></div>
                          <div className={`flex-1 transition-all ${isCurrent ? 'bg-indigo-50 p-2 rounded-xl border border-indigo-100' : ''}`}>
                            <span className={`text-[10px] block ${isCurrent ? 'font-black text-indigo-900 uppercase tracking-tight' : 'font-medium text-slate-400'}`}>
                              {s}
                            </span>
                            {isCurrent && <span className="text-[8px] text-indigo-400 font-bold uppercase tracking-widest">Active Terminal State</span>}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-8 grid grid-cols-2 gap-3">
                     <button className="py-4 bg-slate-900 text-white rounded-[1.25rem] text-[10px] font-black uppercase tracking-widest shadow-xl shadow-slate-900/10 active:scale-95 transition-all">Download Manifest</button>
                     <button className="py-4 bg-indigo-50 text-indigo-600 rounded-[1.25rem] text-[10px] font-black uppercase tracking-widest border border-indigo-100 active:scale-95 transition-all">Support Desk</button>
                  </div>
                </div>
              )}
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-white rounded-[3rem] border border-dashed border-slate-200 opacity-50">
            <i className="fa-solid fa-file-invoice text-4xl mb-4 text-slate-300"></i>
            <p className="text-sm font-bold uppercase tracking-widest text-slate-400">Pipeline Clear</p>
          </div>
        )}
      </div>

      {isModalOpen && isAdmin && (
        <div className="fixed inset-0 z-[200] flex items-end sm:items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom-12">
            <div className="p-8">
              <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">
                    {editingOrder ? 'Update Pipeline' : 'Initiate Supply'}
                  </h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Admin Order Gateway</p>
                </div>
                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full bg-slate-50 text-slate-400 hover:text-slate-900 flex items-center justify-center transition-colors">
                  <i className="fa-solid fa-xmark text-lg"></i>
                </button>
              </div>

              <form onSubmit={handleSave} className="space-y-4 max-h-[60vh] overflow-y-auto no-scrollbar pr-1">
                <div className="space-y-2 mb-4">
                  <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest block mb-1.5 ml-1">Supervisor Agent</label>
                  <select 
                    required
                    className="w-full bg-blue-50/50 border border-blue-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                    value={formData.assignedAgent}
                    onChange={e => setFormData({...formData, assignedAgent: e.target.value})}
                  >
                    <option value="">Select Responsible Agent</option>
                    {AGENT_OPTIONS.map(a => <option key={a} value={a}>{a}</option>)}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Product</label>
                    <input 
                      required
                      value={formData.product}
                      onChange={e => setFormData({...formData, product: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Volume/Quantity</label>
                    <input 
                      required
                      value={formData.quantity}
                      onChange={e => setFormData({...formData, quantity: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Contract Total ($)</label>
                    <input required value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-indigo-600 uppercase tracking-widest block mb-1.5 ml-1">Platform Margin ($)</label>
                    <input required value={formData.commission} onChange={e => setFormData({...formData, commission: e.target.value})} className="w-full bg-indigo-50 border border-indigo-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Supplier Entity</label>
                  <input required value={formData.supplier} onChange={e => setFormData({...formData, supplier: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1.5 ml-1">Buyer Entity</label>
                  <input required value={formData.buyer} onChange={e => setFormData({...formData, buyer: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-[1.25rem] px-4 py-4 text-sm font-bold outline-none" />
                </div>

                <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-[0.15em] text-xs shadow-xl shadow-indigo-500/20 active:scale-95 transition-all mt-6">
                  {editingOrder ? 'Update Master Flow' : 'Authorize Supply Initialization'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Orders;
